/**
 * Factory API 服务
 * Generated by DDF Engine
 */

import request from '@/utils/request'

/**
 * 分页列表
 */
export function getFactoryList(params) {
  return request({
    url: '/api/factory',
    method: 'get',
    params,
  })
}

/**
 * 详情
 */
export function getFactory(id) {
  return request({
    url: `/api/factory/${id}`,
    method: 'get',
  })
}

/**
 * 创建
 */
export function createFactory(data) {
  return request({
    url: '/api/factory',
    method: 'post',
    data,
  })
}

/**
 * 更新
 */
export function updateFactory(id, data) {
  return request({
    url: `/api/factory/${id}`,
    method: 'put',
    data,
  })
}

/**
 * 删除
 */
export function deleteFactory(id) {
  return request({
    url: `/api/factory/${id}`,
    method: 'delete',
  })
}
